import type { Operadora } from './cenarios';

export type StatusPrestador = 'mantido' | 'ganho' | 'perdido';
export type TipoPrestador = 'H' | 'H¹' | 'LAB' | 'M' | 'PA' | 'PS' | 'PS¹' | 'PSA' | 'PSP';

export interface PlanosRede {
  amilOuro: boolean;
  amilOuroII: boolean;
  amilPlatinumR1: boolean;
  amilS450: boolean;
  amilS750R1: boolean;
  porto: boolean;
  sulaClassico100: boolean;
  sulaEspecial100RC: boolean;
  sulaEspecialVital: boolean;
}

export interface Prestador {
  id: string;
  nome: string;
  tipo: TipoPrestador[];
  cidade: string;
  estado: string;
  planos: PlanosRede;
  observacao?: string;
}

// Mapeia nome do plano (de cenarios.ts) para a chave em PlanosRede
export const PLAN_KEY: Record<string, keyof PlanosRede> = {
  'Ouro':           'amilOuro',
  'Ouro II':        'amilOuroII',
  'Platinum R1':    'amilPlatinumR1',
  'S450':           'amilS450',
  'S750 R1':        'amilS750R1',
  'Clássico 100':   'sulaClassico100',
  'Especial 100 RC':'sulaEspecial100RC',
  'Especial Vital': 'sulaEspecialVital',
};

export function getStatusForPlan(p: Prestador, planNome: string): StatusPrestador | null {
  const key = PLAN_KEY[planNome];
  if (!key) return null;
  const planHas = p.planos[key];
  const portoHas = p.planos.porto;
  if (portoHas && planHas) return 'mantido';
  if (!portoHas && planHas) return 'ganho';
  if (portoHas && !planHas) return 'perdido';
  return null;
}

